{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from single-recipient to multi-recipient shipments. This is a fundamental change to the Shipment aggregate root — one of the most central entities in any logistics domain. The change affects 2 million existing production records and external partner API contracts.",
    "bounded_context": "Shipment Fulfillment — the bounded context that owns the lifecycle of a shipment from creation through delivery. This change also ripples into Partner Integration (external APIs), Notification (delivery preferences per recipient), and Billing (cost allocation across recipients).",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from an origin to one or more delivery destinations. The aggregate root of the fulfillment context." },
      { "term": "Recipient", "definition": "A party who receives delivery of goods at a specified address. Identified by name, address, phone number, and now also delivery preferences." },
      { "term": "Delivery Preference", "definition": "A Recipient-level configuration that governs how and when delivery should occur (e.g., time windows, signature requirements, safe-place instructions, contactless delivery)." },
      { "term": "Primary Recipient", "definition": "In a multi-recipient shipment, the recipient designated as the main point of contact. Must be explicitly defined if business processes (notifications, billing, disputes) require a single accountable party." },
      { "term": "Shipment Leg", "definition": "A segment of a multi-recipient shipment's route representing transit between two consecutive delivery points." },
      { "term": "Delivery Attempt", "definition": "A single attempt to deliver goods to a specific Recipient. In multi-recipient shipments, each Recipient has independent delivery attempts." },
      { "term": "Shipment Status", "definition": "The current state of the shipment lifecycle. In multi-recipient shipments, this must now reconcile potentially divergent per-recipient delivery statuses into a coherent aggregate status." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient. Zero-recipient shipments are invalid and must be rejected at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no delivery destination — it is logically incoherent and would corrupt downstream routing, billing, and tracking. This is a structural integrity constraint.",
      "testable_assertion": "Any attempt to create or update a Shipment to have zero Recipients must be rejected with a validation error."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment must have a valid name, address, and phone number. Delivery preferences are optional and default to standard delivery if unspecified.",
      "invariant": true,
      "invariant_justification": "Name and address are required for physical delivery. Phone number is required for courier contact upon arrival. Without these, delivery cannot be attempted. This is a physical-world constraint that no policy can override.",
      "testable_assertion": "A Recipient missing name, address, or phone number must be rejected at validation time, regardless of whether delivery preferences are provided."
    },
    {
      "id": "BR-3",
      "rule": "Existing single-recipient shipments must remain valid and queryable without data loss after the model migration. The new model must be backward-compatible: a shipment with one recipient behaves identically to the legacy model.",
      "invariant": true,
      "invariant_justification": "Losing or corrupting 2 million production records is a data integrity violation. Backward compatibility preserves system consistency during and after migration.",
      "testable_assertion": "After migration, querying any of the 2 million existing shipments returns the same recipient data (name, address, phone) as before migration, now represented as a single-element recipient collection."
    },
    {
      "id": "BR-4",
      "rule": "A Shipment with multiple Recipients must define a delivery sequence (ordered list). The courier delivers in sequence unless route optimization overrides are explicitly enabled.",
      "invariant": false,
      "invariant_justification": "Delivery sequence is a business policy that affects logistics efficiency but is not a structural constraint. Operations leadership could decide to allow unordered multi-drop at any time.",
      "testable_assertion": "A multi-recipient Shipment stores Recipients in an explicit ordered sequence, and the routing engine respects this order by default."
    },
    {
      "id": "BR-5",
      "rule": "Each Recipient's delivery status is tracked independently. A Shipment's aggregate status is derived from the individual Recipient delivery statuses.",
      "invariant": true,
      "invariant_justification": "If Recipient A receives their delivery but Recipient B does not, the Shipment cannot be marked 'Delivered.' Conflating independent delivery outcomes into a single status would corrupt tracking data and misrepresent fulfillment state.",
      "testable_assertion": "A Shipment is only marked 'Delivered' when ALL Recipients have status 'Delivered.' If any Recipient has status 'Failed' or 'Pending,' the Shipment aggregate status reflects this accurately."
    },
    {
      "id": "BR-6",
      "rule": "External partner APIs must continue to receive shipment data in the current single-recipient format until partners have migrated to a new API version. Multi-recipient shipments sent to legacy partners must be projected into the legacy format.",
      "invariant": false,
      "invariant_justification": "This is a compatibility policy driven by partner contracts and migration timelines, not a structural constraint. Once all partners migrate, this rule is retired.",
      "testable_assertion": "When a multi-recipient shipment is sent to a partner on the legacy API, the payload contains only the primary recipient's data and conforms to the existing schema."
    },
    {
      "id": "BR-7",
      "rule": "Delivery preferences are scoped to the individual Recipient, not the Shipment. Two Recipients on the same Shipment may have conflicting preferences (e.g., one requires signature, one allows safe-place).",
      "invariant": true,
      "invariant_justification": "Delivery preferences encode the recipient's real-world constraints and consent. Merging or overriding them at the shipment level would violate individual recipient instructions and potentially breach delivery contracts.",
      "testable_assertion": "Each Recipient's delivery preferences are stored, enforced, and displayed independently. The courier app shows per-recipient instructions at each delivery stop."
    },
    {
      "id": "BR-8",
      "rule": "A Recipient address must not appear more than once on the same Shipment. Duplicate addresses on a single Shipment indicate a data entry error.",
      "invariant": false,
      "invariant_justification": "This is a data quality policy. There could be legitimate edge cases (two different people at the same address receiving different items from the same shipment), though this would be unusual. A VP could override this if a valid business case emerges.",
      "testable_assertion": "Creating a Shipment with two Recipients at the same address raises a warning. If enforced as a hard rule, it rejects the request."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A shipment is being created",
      "when": "The request includes one or more Recipients, each with name, address, phone, and optional delivery preferences",
      "then": "The shipment is created successfully with all Recipients stored in order, and delivery preferences default to 'standard' where unspecified"
    },
    {
      "id": "AC-2",
      "given": "A shipment is being created",
      "when": "The request includes zero Recipients",
      "then": "The request is rejected with a validation error indicating at least one Recipient is required"
    },
    {
      "id": "AC-3",
      "given": "The data migration has been applied to the 2 million existing shipments",
      "when": "An existing shipment is queried via any API or internal service",
      "then": "The shipment returns its original recipient data as a single-element collection with default delivery preferences, and no data is lost or altered"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient shipment exists and Recipient 1 has been delivered but Recipient 2 has not",
      "when": "The shipment status is queried",
      "then": "The shipment aggregate status is 'Partially Delivered' (or equivalent), not 'Delivered'"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient shipment is synced to an external partner using the legacy API",
      "when": "The partner API receives the shipment payload",
      "then": "The payload conforms to the existing single-recipient schema, using the primary recipient's data, and does not break the partner's integration"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient shipment with Recipients who have different delivery preferences",
      "when": "A courier views the shipment on their device",
      "then": "Each delivery stop shows the specific Recipient's name, address, phone, and individual delivery preferences"
    },
    {
      "id": "AC-7",
      "given": "A Recipient on a multi-recipient shipment is removed",
      "when": "The removal would result in zero Recipients on the Shipment",
      "then": "The removal is rejected, preserving the at-least-one-recipient invariant"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient shipment where one Recipient refuses delivery but others accept",
      "expected_behavior": "The refusing Recipient is marked 'Refused/Failed.' The shipment status reflects partial fulfillment. Return logistics for the refused portion must be triggered independently without affecting other Recipients' deliveries."
    },
    {
      "scenario": "A shipment originally created with one Recipient has additional Recipients added after the courier is already en route",
      "expected_behavior": "The system must define a cutoff policy: can Recipients be added to an in-transit shipment? If yes, the courier must be re-notified and the route recalculated. If no, the addition is rejected with a clear status-based validation error."
    },
    {
      "scenario": "Two Recipients on the same shipment have conflicting time-window delivery preferences that make sequential delivery impossible within the same day",
      "expected_behavior": "The system should detect the scheduling conflict at shipment creation time and either warn the sender or reject the combination. The courier should not be dispatched on a route that is physically impossible to fulfill."
    },
    {
      "scenario": "An external partner queries a multi-recipient shipment via the legacy API, then updates it — potentially overwriting multi-recipient data with single-recipient data",
      "expected_behavior": "Legacy API writes must be scoped to the primary Recipient only and must not destroy other Recipients' data. Alternatively, legacy API writes on multi-recipient shipments should be rejected with a 409 Conflict directing the partner to the new API version."
    },
    {
      "scenario": "A Recipient's address is updated on a multi-recipient shipment after partial delivery has already occurred to other Recipients",
      "expected_behavior": "The address change is permitted only for Recipients whose delivery status is still 'Pending.' Recipients already delivered or in-transit cannot have their address changed."
    },
    {
      "scenario": "Billing and pricing for a multi-recipient shipment — is it one charge or multiple?",
      "expected_behavior": "This must be explicitly defined by the product team. Multi-drop shipments typically cost more than single-recipient shipments due to additional stops. The billing model (per-stop surcharge vs. flat multi-recipient rate) must be decided before implementation."
    },
    {
      "scenario": "Notifications (SMS/email) for shipment events — who gets notified on a multi-recipient shipment?",
      "expected_behavior": "Each Recipient receives notifications only for their own delivery events (out for delivery to them, delivered to them, failed for them). The Sender receives aggregate notifications. No Recipient should see another Recipient's personal data."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments unlock a new revenue stream (multi-drop deliveries) and can increase average order value. However, pricing model changes are required — the existing single-delivery pricing does not account for additional stops. Incorrect billing logic could lead to revenue leakage or customer disputes. Migration costs are non-trivial given 2M production records.",
    "operational": "Significant operational complexity increase: couriers now manage multi-stop routes per shipment, dispatch routing becomes a multi-destination optimization problem, and delivery tracking must handle per-recipient states. Support teams need training on the new model. Existing reporting dashboards that assume one-recipient-per-shipment will break or show misleading metrics.",
    "user": "Senders gain flexibility to ship to multiple recipients in one transaction. Recipients get personalized delivery preferences. However, courier experience increases in complexity — the courier app must clearly separate per-recipient instructions or risk mis-delivery. Poor UX here directly causes failed deliveries.",
    "risk": "HIGH. This is a change to the core aggregate root of the domain. Risks include: (1) data migration failure or corruption of 2M records, (2) breaking external partner integrations, (3) status tracking bugs that misrepresent delivery state, (4) privacy leakage between recipients on the same shipment, (5) billing errors on multi-recipient shipments. Each of these can cause customer-visible incidents.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain multi-recipient capability but must learn new shipment creation flow. Existing single-recipient workflows must remain unchanged." },
      { "group": "Recipients", "impact": "Gain personalized delivery preferences. Risk: privacy — a recipient must not see other recipients' data on the same shipment." },
      { "group": "Couriers/Drivers", "impact": "Must handle multi-stop deliveries with per-recipient instructions. App UX must clearly delineate stops. Training required." },
      { "group": "External Partners", "impact": "Legacy API contract must be preserved. Partners need migration path to new API version. Breaking changes will violate SLAs." },
      { "group": "Customer Support", "impact": "Must handle new categories of issues: partial deliveries, per-recipient disputes, multi-recipient billing questions. Tooling and training updates needed." },
      { "group": "Finance/Billing", "impact": "Pricing model must be updated for multi-drop shipments. Revenue recognition may change if partial delivery creates partial fulfillment scenarios." },
      { "group": "Data/Analytics", "impact": "All dashboards and metrics that assume 1:1 shipment-to-recipient will produce incorrect results. KPIs like 'deliveries per shipment' fundamentally change meaning." }
    ]
  },

  "confidence": {
    "level": 62,
    "reasoning": "The request clearly defines the model change (1-to-many Recipients with delivery preferences), and I have high confidence in the core invariants and migration requirements. However, confidence is capped because several critical business decisions are unspecified: (1) the billing/pricing model for multi-recipient shipments, (2) whether Recipients can be modified on in-transit shipments, (3) the definition and selection logic for 'Primary Recipient' for legacy API projection, (4) the privacy model between co-recipients, and (5) what 'delivery preferences' specifically includes. These gaps affect acceptance criteria completeness.",
    "high_confidence_areas": [
      "At-least-one-recipient invariant",
      "Backward compatibility requirement for 2M existing records",
      "Independent per-recipient delivery status tracking",
      "Legacy API compatibility requirement for external partners",
      "Per-recipient delivery preference scoping"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient shipments (not specified)",
      "Primary Recipient designation rules (not specified)",
      "Exact composition of 'delivery preferences' (not specified)",
      "In-transit modification policy for recipients (not specified)",
      "Privacy model between co-recipients on same shipment (not specified)"
    ],
    "assumptions": [
      "The Recipient collection on a Shipment is ordered and the order has business meaning (delivery sequence)",
      "Existing single-recipient shipments will be migrated to the new model as single-element collections rather than maintained in a legacy schema",
      "External partner APIs are versioned and a new version can be introduced without breaking existing integrations",
      "Delivery preferences are Recipient-level, not Shipment-level, based on the spec wording 'each Recipient can have different delivery preferences'"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define what 'delivery preferences' includes. This term could range from simple time-window preferences to complex configurations including signature requirements, safe-place authorization, contactless delivery, age verification, and more. The scope of this term materially affects the data model, UI, and courier workflow.",
      "affected_stakeholders": ["Senders/Shippers", "Recipients", "Couriers/Drivers", "Product Team"],
      "options": ["Define a minimal MVP set (e.g., time window + signature required)", "Define an extensible preference schema that can grow over time", "Defer preferences to a follow-up iteration and ship multi-recipient with no preferences first"],
      "recommendation": "Define a minimal, explicit set of delivery preferences for v1 (time window, signature required, safe-place instructions) with an extensible schema to add more later."
    },
    {
      "type": "ambiguity",
      "description": "No 'Primary Recipient' concept is defined, but the legacy API projection to external partners requires selecting one recipient to represent the shipment. Without a clear rule for which recipient is 'primary,' the legacy projection is undefined.",
      "affected_stakeholders": ["External Partners", "Product Team", "Engineering"],
      "options": ["First recipient in the ordered list is always primary", "Sender explicitly designates a primary recipient at creation time", "Reject multi-recipient shipments from being synced to legacy partners entirely"],
      "recommendation": "Require the sender to explicitly designate a Primary Recipient at shipment creation time. Default to the first recipient if unspecified."
    },
    {
      "type": "missing_context",
      "description": "The billing and pricing model for multi-recipient shipments is not defined. This is a prerequisite for implementation — without it, shipments can be created but not invoiced correctly, leading to revenue leakage or incorrect charges.",
      "affected_stakeholders": ["Finance/Billing", "Senders/Shippers", "Product Team"],
      "options": ["Per-stop surcharge on top of base shipment price", "Tiered pricing based on number of recipients", "Distance-based pricing across all stops", "Defer billing changes and charge single-recipient rate initially"],
      "recommendation": "Define the billing model before shipping multi-recipient to production. At minimum, apply a per-additional-stop surcharge to avoid revenue leakage."
    },
    {
      "type": "ambiguity",
      "description": "The privacy model between co-recipients on the same shipment is not addressed. Can Recipient A see Recipient B's name, address, or delivery status? Tracking pages, notifications, and API responses must enforce appropriate data boundaries.",
      "affected_stakeholders": ["Recipients", "Legal/Compliance", "Product Team"],
      "options": ["Full isolation: recipients see only their own data", "Sender-visible: sender sees all, each recipient sees only their own", "Shared tracking: all recipients see all delivery statuses but not personal details"],
      "recommendation": "Full isolation by default — each recipient sees only their own delivery data. Sender sees all. This is the safest default for privacy compliance."
    }
  ],

  "rejection_reasons": []
}

